-- SQL schema for Klinik Atma Database\n\nCREATE TABLE users (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    username VARCHAR(50) NOT NULL UNIQUE,\n    password VARCHAR(255) NOT NULL,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE pasien (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    name VARCHAR(100) NOT NULL,\n    birth_date DATE NOT NULL,\n    gender ENUM('L', 'P') NOT NULL,\n    contact_number VARCHAR(15) NOT NULL\n);\n\nCREATE TABLE dokter (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    name VARCHAR(100) NOT NULL,\n    specialization VARCHAR(100) NOT NULL,\n    contact_number VARCHAR(15) NOT NULL\n);\n\nCREATE TABLE antrian (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    pasien_id INT NOT NULL,\n    dokter_id INT NOT NULL,\n    status ENUM('menunggu', 'selesai') DEFAULT 'menunggu',\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (pasien_id) REFERENCES pasien(id),\n    FOREIGN KEY (dokter_id) REFERENCES dokter(id)\n);\n\nCREATE TABLE jadwal_konsultasi (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    dokter_id INT NOT NULL,\n    jadwal DATETIME NOT NULL,\n    keterangan TEXT,\n    FOREIGN KEY (dokter_id) REFERENCES dokter(id)\n);\n\n-- Sample data\n\nINSERT INTO users (username, password) VALUES\n    ('admin', 'admin123'),\n    ('user1', 'user1234');\n\nINSERT INTO pasien (name, birth_date, gender, contact_number) VALUES\n    ('Ahmad', '1990-01-01', 'L', '08123456789'),\n    ('Siti', '1992-02-15', 'P', '08987654321');\n\nINSERT INTO dokter (name, specialization, contact_number) VALUES\n    ('Dr. Budi', 'Psikiater', '08123456780'),\n    ('Dr. Siti', 'Psikolog', '08987654322');\n\nINSERT INTO antrian (pasien_id, dokter_id, status) VALUES\n    (1, 1, 'menunggu'),\n    (1, 2, 'selesai'),\n    (2, 1, 'menunggu');\n\nINSERT INTO jadwal_konsultasi (dokter_id, jadwal, keterangan) VALUES\n    (1, '2026-04-07 09:00:00', 'Konsultasi Umum'),\n    (2, '2026-04-07 10:00:00', 'Konsultasi Khusus');\n